import { useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'


// Delete
export const deleteRow = async (endpoint, id) => {
    try {
        await constFlaskURL.delete(`${endpoint}?id=${id}`);
        // fetchTableData();
    } catch (error) {
        console.log(error);
    } 
}

// Get
export const getRow = async (endpoint, id) => {
    const navigate = useNavigate();

    try {
        await constFlaskURL.get(`${endpoint}?id=${id}`);
        navigate(`${endpoint}/edit/${id}`);
    } catch (error) {
        console.log(error);
    } 
}
